Consider the following program:
void find (struct Node *node)
{
    struct Node *ptr, *q;
    if (node == NULL) return;
    find (node -> left);
    find (node -> right);
    ptr = node -> left;
    q = (struct Node *) malloc (size of (Node));
    q -> right = NULL;
    q -> left = NULL;
    q -> data = node -> data;
    node -> left = q;
    node -> left -> left = ptr;
}
If the root of following tree is passed to the above function, find the sum of all keys in the resultant tree produced by find( ).
